using System;

class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: empty environment variables are now
        // distinguished from unset ones. GetEnvironmentVariable returns ""
        // instead of null for `export MY_FLAG=""`.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly empty");
        }
    }
}

